// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




// Task card sub-component
interface TaskCardProps {
  task: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string };
  columns: Array<{ id?: string; name?: string }>;
  onMove: (taskId: string, targetColumn: string) => void;
  onEdit: (taskId: string, title: string) => void;
}

function TaskCard({ task, columns, onMove, onEdit }: TaskCardProps) {
  const [isEditing, setIsEditing] = useState(false);
  const [editTitle, setEditTitle] = useState(task.title || '');
  const [showMoveMenu, setShowMoveMenu] = useState(false);

  const handleEditSave = () => {
    if (editTitle.trim() && task.id) {
      onEdit(task.id, editTitle);
      setIsEditing(false);
    }
  };

  const getPriorityColor = (): string => {
    switch (task.priority) {
      case 'high': return 'var(--ggui-color-error-500)';
      case 'medium': return 'var(--ggui-color-warning-500)';
      case 'low': return 'var(--ggui-color-success-500)';
      default: return 'var(--ggui-color-outline)';
    }
  };

  const getPriorityVariant = (): 'error' | 'warning' | 'success' | 'default' => {
    switch (task.priority) {
      case 'high': return 'error';
      case 'medium': return 'warning';
      case 'low': return 'success';
      default: return 'default';
    }
  };

  return (
    <Card shadow="sm" padding="var(--ggui-spacing-3)" radius="md">
      <Stack gap="var(--ggui-spacing-2)">
        {isEditing ? (
          <Stack gap="var(--ggui-spacing-2)">
            <Input
              label="Edit task"
              value={editTitle}
              onChange={setEditTitle}
              size="sm"
            />
            <Row gap="var(--ggui-spacing-1)" justify="end">
              <Button
                size="xs"
                variant="ghost"
                onClick={() => setIsEditing(false)}
              >
                Cancel
              </Button>
              <Button
                size="xs"
                variant="primary"
                onClick={handleEditSave}
              >
                Save
              </Button>
            </Row>
          </Stack>
        ) : (
          <>
            <Row gap="var(--ggui-spacing-2)" align="center" justify="between">
              <Text
                variant="body"
                weight="medium"
                truncate
                as={Clickable}
                onClick={() => {
                  setEditTitle(task.title || '');
                  setIsEditing(true);
                }}
                style={{ flex: 1, cursor: 'pointer' }}
              >
                {task.title || 'Untitled'}
              </Text>
              <Button
                size="xs"
                variant="ghost"
                onClick={() => {
                  setEditTitle(task.title || '');
                  setIsEditing(true);
                }}
              >
                Edit
              </Button>
            </Row>

            {task.priority && (
              <Badge variant={getPriorityVariant()} size="sm">
                {task.priority.charAt(0).toUpperCase() + task.priority.slice(1)}
              </Badge>
            )}

            <Row gap="var(--ggui-spacing-2)" align="center">
              {task.assignee && (
                <Avatar name={task.assignee} size="sm" shape="circle" />
              )}
              {task.dueDate && (
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                  {new Date(task.dueDate).toLocaleDateString()}
                </Text>
              )}
            </Row>

            <Box position="relative">
              <Dropdown
                trigger={<Button size="xs" variant="outline">Move</Button>}
                options={columns
                  .filter(c => c.id !== task.column)
                  .map(c => ({ value: c.id || '', label: c.name || '' }))}
                value={task.column || ''}
                onChange={(targetColumn) => {
                  if (task.id) onMove(task.id, targetColumn);
                }}
                placement="bottom-end"
              />
            </Box>
          </>
        )}
      </Stack>
    </Card>
  );
}

export default function Component(props: Props) {
  // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate');

  // Streams — real-time from agent
  const taskChanged = useStream<StreamTaskChanged>('taskChanged');

  // Local state
  const [tasks, setTasks] = useState(props.tasks);
  const [showAddForm, setShowAddForm] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  // Sync tasks from props and stream
  useEffect(() => {
    setTasks(props.tasks);
  }, [props.tasks]);

  useEffect(() => {
    if (taskChanged.latest) {
      const { action, task } = taskChanged.latest;
      if (action === 'create' && task) {
        setTasks(prev => [...prev, task]);
      } else if (action === 'move' && task) {
        setTasks(prev =>
          prev.map(t => t.id === task.id ? { ...t, column: task.column } : t)
        );
      } else if (action === 'edit' && task) {
        setTasks(prev =>
          prev.map(t => t.id === task.id ? { ...t, ...task } : t)
        );
      } else if (action === 'delete' && task) {
        setTasks(prev => prev.filter(t => t.id !== task.id));
      }
    }
  }, [taskChanged.latest]);

  const handleMoveTask = useCallback((taskId: string, targetColumn: string) => {
    setTasks(prev =>
      prev.map(t => t.id === taskId ? { ...t, column: targetColumn } : t)
    );
    taskUpdate({ action: 'move', taskId, data: { column: targetColumn } });
  }, [taskUpdate]);

  const handleEditTask = useCallback((taskId: string, title: string) => {
    setTasks(prev =>
      prev.map(t => t.id === taskId ? { ...t, title } : t)
    );
    taskUpdate({ action: 'edit', taskId, data: { column: tasks.find(t => t.id === taskId)?.column || 'todo' } });
  }, [tasks, taskUpdate]);

  const handleAddTask = useCallback((columnId: string) => {
    if (!newTaskTitle.trim()) return;
    const newTask = {
      id: `task-${Date.now()}`,
      title: newTaskTitle,
      priority: newTaskPriority as 'low' | 'medium' | 'high',
      column: columnId,
    };
    setTasks(prev => [...prev, newTask]);
    taskUpdate({ action: 'create', taskId: newTask.id, data: { column: columnId } });
    setNewTaskTitle('');
    setNewTaskPriority('medium');
    setShowAddForm(null);
  }, [newTaskTitle, newTaskPriority, taskUpdate]);

  const completedCount = useMemo(() => {
    const doneColumn = props.columns.find(c => c.id === 'done');
    return tasks.filter(t => t.column === doneColumn?.id).length;
  }, [tasks, props.columns]);

  const getTasksByColumn = useCallback((columnId?: string) => {
    return tasks.filter(t => t.column === columnId);
  }, [tasks]);

  return (
    <Container maxWidth="2xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Summary bar */}
        <Box background="var(--ggui-color-primary-50)" padding="var(--ggui-spacing-4)" borderRadius="var(--ggui-shape-radius-lg)">
          <Row gap="var(--ggui-spacing-4)" justify="between" align="center">
            <Stack gap="var(--ggui-spacing-1)">
              <Text variant="label" color="var(--ggui-color-primary-700)">Task Summary</Text>
              <Row gap="var(--ggui-spacing-3)">
                <Text variant="body" weight="semibold" color="var(--ggui-color-onSurface)">
                  Total: {tasks.length}
                </Text>
                <Divider orientation="vertical" margin="var(--ggui-spacing-1)" />
                <Text variant="body" weight="semibold" color="var(--ggui-color-success-600)">
                  Completed: {completedCount}
                </Text>
              </Row>
            </Stack>
          </Row>
        </Box>

        {/* Kanban columns */}
        <Row gap="var(--ggui-spacing-4)" align="start" wrap>
          {props.columns.map(column => {
            const columnTasks = getTasksByColumn(column.id);
            return (
              <Box
                key={column.id}
                padding="var(--ggui-spacing-4)"
                background="var(--ggui-color-surfaceVariant)"
                borderRadius="var(--ggui-shape-radius-lg)"
                style={{ minWidth: '320px', maxWidth: '400px', flex: '1 1 320px', minHeight: '600px', display: 'flex', flexDirection: 'column' }}
              >
                <Stack gap="var(--ggui-spacing-4)" style={{ flex: 1 }}>
                  {/* Column header */}
                  <Row gap="var(--ggui-spacing-2)" justify="between" align="center">
                    <Heading level={4} color="var(--ggui-color-onSurface)">
                      {column.name}
                    </Heading>
                    <Badge variant="default" size="sm">
                      {columnTasks.length}
                    </Badge>
                  </Row>

                  {/* Task list */}
                  <Stack
                    gap="var(--ggui-spacing-2)"
                    style={{
                      flex: 1,
                      overflowY: 'auto',
                      paddingRight: 'var(--ggui-spacing-1)',
                    }}
                  >
                    {columnTasks.length > 0 ? (
                      columnTasks.map(task => (
                        <TaskCard
                          key={task.id}
                          task={task}
                          columns={props.columns}
                          onMove={handleMoveTask}
                          onEdit={handleEditTask}
                        />
                      ))
                    ) : (
                      <Text
                        variant="caption"
                        color="var(--ggui-color-onSurfaceVariant)"
                        align="center"
                      >
                        No tasks
                      </Text>
                    )}
                  </Stack>

                  {/* Add task button/form */}
                  {showAddForm === column.id ? (
                    <Card shadow="sm" padding="var(--ggui-spacing-3)" radius="md" background="var(--ggui-color-surface)">
                      <Stack gap="var(--ggui-spacing-2)">
                        <Input
                          label="Task title"
                          value={newTaskTitle}
                          onChange={setNewTaskTitle}
                          placeholder="Enter task title"
                          size="sm"
                        />
                        <Select
                          label="Priority"
                          value={newTaskPriority}
                          onChange={(val) => setNewTaskPriority(val as 'low' | 'medium' | 'high')}
                          options={[
                            { value: 'low', label: 'Low' },
                            { value: 'medium', label: 'Medium' },
                            { value: 'high', label: 'High' },
                          ]}
                          size="sm"
                        />
                        <Row gap="var(--ggui-spacing-1)" justify="end">
                          <Button
                            size="xs"
                            variant="ghost"
                            onClick={() => {
                              setShowAddForm(null);
                              setNewTaskTitle('');
                              setNewTaskPriority('medium');
                            }}
                          >
                            Cancel
                          </Button>
                          <Button
                            size="xs"
                            variant="primary"
                            onClick={() => handleAddTask(column.id || 'todo')}
                          >
                            Add
                          </Button>
                        </Row>
                      </Stack>
                    </Card>
                  ) : (
                    <Button
                      variant="ghost"
                      size="sm"
                      onClick={() => setShowAddForm(column.id || null)}
                      fullWidth
                    >
                      + Add Task
                    </Button>
                  )}
                </Stack>
              </Box>
            );
          })}
        </Row>
      </Stack>
    </Container>
  );
}
